import 'dart:convert';

class UserModel {
  final String id;
  final String email;
  final String displayName;
  final String? avatarUrl;
  final Map<String, dynamic>? metadata;

  UserModel({
    required this.id,
    required this.email,
    required this.displayName,
    this.avatarUrl,
    this.metadata,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'email': email,
        'displayName': displayName,
        'avatarUrl': avatarUrl,
        'metadata': metadata,
      };

  factory UserModel.fromJson(Map<String, dynamic> json) => UserModel(
        id: json['id'] as String,
        email: json['email'] as String,
        displayName: json['displayName'] as String,
        avatarUrl: json['avatarUrl'] as String?,
        metadata: json['metadata'] as Map<String, dynamic>?,
      );

  String toJsonString() => jsonEncode(toJson());

  factory UserModel.fromJsonString(String jsonString) =>
      UserModel.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);

  @override
  String toString() => 'UserModel(id: $id, email: $email, displayName: $displayName)';
}

// lib/models/auth_tokens.dart
import 'dart:convert';

class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isAboutToExpire =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() => {
        'accessToken': accessToken,
        'refreshToken': refreshToken,
        'expiresAt': expiresAt.toIso8601String(),
      };

  factory AuthTokens.fromJson(Map<String, dynamic> json) => AuthTokens(
        accessToken: json['accessToken'] as String,
        refreshToken: json['refreshToken'] as String,
        expiresAt: DateTime.parse(json['expiresAt'] as String),
      );

  String toJsonString() => jsonEncode(toJson());

  factory AuthTokens.fromJsonString(String jsonString) =>
      AuthTokens.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);
}

// lib/services/secure_storage_service.dart
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecureStorageService {
  static const _accessTokenKey = 'auth_access_token';
  static const _refreshTokenKey = 'auth_refresh_token';
  static const _tokenExpiryKey = 'auth_token_expiry';

  final FlutterSecureStorage _secureStorage;

  SecureStorageService({FlutterSecureStorage? secureStorage})
      : _secureStorage = secureStorage ??
            const FlutterSecureStorage(
              aOptions: AndroidOptions(
                encryptedSharedPreferences: true,
              ),
              iOptions: IOSOptions(
                accessibility: KeychainAccessibility.first_unlock_this_device,
              ),
            );

  Future<void> saveAccessToken(String token) async {
    await _secureStorage.write(key: _accessTokenKey, value: token);
  }

  Future<String?> getAccessToken() async {
    return await _secureStorage.read(key: _accessTokenKey);
  }

  Future<void> saveRefreshToken(String token) async {
    await _secureStorage.write(key: _refreshTokenKey, value: token);
  }

  Future<String?> getRefreshToken() async {
    return await _secureStorage.read(key: _refreshTokenKey);
  }

  Future<void> saveTokenExpiry(DateTime expiry) async {
    await _secureStorage.write(
        key: _tokenExpiryKey, value: expiry.toIso8601String());
  }

  Future<DateTime?> getTokenExpiry() async {
    final expiryString = await _secureStorage.read(key: _tokenExpiryKey);
    if (expiryString == null) return null;
    return DateTime.tryParse(expiryString);
  }

  Future<void> clearAllTokens() async {
    await _secureStorage.delete(key: _accessTokenKey);
    await _secureStorage.delete(key: _refreshTokenKey);
    await _secureStorage.delete(key: _tokenExpiryKey);
  }

  Future<void> clearAll() async {
    await _secureStorage.deleteAll();
  }
}

// lib/services/user_preferences_service.dart
import 'dart:convert';
import 'package:shared_preferences/shared_preferences.dart';

class UserPreferencesService {
  static const _userDataKey = 'user_data';
  static const _isLoggedInKey = 'is_logged_in';
  static const _lastLoginKey = 'last_login';
  static const _onboardingCompleteKey = 'onboarding_complete';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get _preferences async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  /// Save non-sensitive user profile data
  Future<void> saveUserData(Map<String, dynamic> userData) async {
    final prefs = await _preferences;
    // Strip any sensitive fields before storing in shared_preferences
    final sanitized = _sanitizeUserData(userData);
    await prefs.setString(_userDataKey, jsonEncode(sanitized));
  }

  Future<Map<String, dynamic>?> getUserData() async {
    final prefs = await _preferences;
    final jsonString = prefs.getString(_userDataKey);
    if (jsonString == null) return null;
    return jsonDecode(jsonString) as Map<String, dynamic>;
  }

  Future<void> setLoggedIn(bool value) async {
    final prefs = await _preferences;
    await prefs.setBool(_isLoggedInKey, value);
    if (value) {
      await prefs.setString(_lastLoginKey, DateTime.now().toIso8601String());
    }
  }

  Future<bool> isLoggedIn() async {
    final prefs = await _preferences;
    return prefs.getBool(_isLoggedInKey) ?? false;
  }

  Future<DateTime?> getLastLogin() async {
    final prefs = await _preferences;
    final dateString = prefs.getString(_lastLoginKey);
    if (dateString == null) return null;
    return DateTime.tryParse(dateString);
  }

  Future<void> setOnboardingComplete(bool value) async {
    final prefs = await _preferences;
    await prefs.setBool(_onboardingCompleteKey, value);
  }

  Future<bool> isOnboardingComplete() async {
    final prefs = await _preferences;
    return prefs.getBool(_onboardingCompleteKey) ?? false;
  }

  Future<void> clearUserData() async {
    final prefs = await _preferences;
    await prefs.remove(_userDataKey);
    await prefs.remove(_isLoggedInKey);
    await prefs.remove(_lastLoginKey);
  }

  Future<void> clearAll() async {
    final prefs = await _preferences;
    await prefs.clear();
  }

  /// Remove sensitive fields that should never be in shared_preferences
  Map<String, dynamic> _sanitizeUserData(Map<String, dynamic> data) {
    final sensitiveKeys = {
      'password',
      'token',
      'accessToken',
      'refreshToken',
      'secret',
      'pin',
      'ssn',
      'creditCard',
      'cardNumber',
      'cvv',
      'access_token',
      'refresh_token',
      'api_key',
      'apiKey',
    };

    return Map.fromEntries(
      data.entries.where(
        (entry) => !sensitiveKeys.contains(entry.key.toLowerCase()),
      ),
    );
  }
}

