}

class LoginResult {
  final bool isSuccess;
  final String? errorMessage;

  LoginResult._({required this.isSuccess, this.errorMessage});

  factory LoginResult.success() => LoginResult._(isSuccess: true);
  factory LoginResult.failure(String message) =>
      LoginResult._(isSuccess: false, errorMessage: message);
}

// lib/services/auth_interceptor.dart
// Example HTTP interceptor for automatic token injection and refresh

class AuthInterceptor {
  final AuthManager _authManager;

  AuthInterceptor(this._authManager);

  /// Get headers with valid auth token
  Future<Map<String, String>> getAuthHeaders() async {
    final token = await _authManager.getValidAccessToken();
    if (token == null) {
      throw AuthException('No valid access token available');
    }

    return {
      'Authorization': 'Bearer $token',
      'Content-Type': 'application/json',
    };
  }

  /// Handle API response status codes
  Future<void> handleResponseStatus(int statusCode) async {
    if (statusCode == 401) {
      // Token might be invalid, try refresh
      final refreshed = await _authManager.refreshAccessToken();
      if (!refreshed) {
        await _authManager.forceLogout();
        throw AuthException('Session expired. Please login again.');
      }
    } else if (statusCode == 403) {
      throw AuthException('Access denied.');
    }
  }
}

class AuthException implements Exception {
  final String message;
  AuthException(this.message);

  @override
  String toString() => 'AuthException: $message';
}

