import 'package:flutter/material.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  final authManager = AuthManager();
  await authManager.initialize();

  runApp(MyApp(authManager: authManager));
}

class MyApp extends StatelessWidget {
  final AuthManager authManager;

  const MyApp({super.key, required this.authManager});

  @override
  Widget build(BuildContext context) {
    return ListenableBuilder(
      listenable: authManager,
      builder: (context, _) {
        return MaterialApp(
          title: 'Auth Demo',
          theme: ThemeData(
            colorSchemeSeed: Colors.blue,
            useMaterial3: true,
          ),
          home: _buildHome(),
        );
      },
    );
  }

  Widget _buildHome() {
    switch (authManager.authState) {
      case AuthState.unknown:
        return const SplashScreen();
      case AuthState.authenticated:
        return HomeScreen(authManager: authManager);
      case AuthState.unauthenticated:
      case AuthState.tokenExpired:
        return LoginScreen(authManager: authManager);
    }
  }
}

class SplashScreen extends StatelessWidget {
  const SplashScreen({super.key});

  @override
