                      ),
                      const SizedBox(height: 8),
                      Text('Auth State: ${authManager.authState.name}'),
                      Text('User ID: ${user?.id ?? 'N/A'}'),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 24),
              OutlinedButton.icon(
                onPressed: () => authManager.logout(),
                icon: const Icon(Icons.logout),
                label: const Text('Sign Out'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}